validate_doc_update:
function (newDoc, oldDoc, userCtx, secObj) {
  if (newDoc._deleted === true) return;
  if (newDoc._id && newDoc._id.indexOf("_design/") === 0) return;
  function err(field, msg) { throw { forbidden: "WO validation failed [" + field + "]: " + msg }; }
  function isStr(v) { return typeof v === "string" && v.length > 0; }
  function present(v) { return v !== undefined && v !== null && v !== ""; }

  if (newDoc.type !== "workorder") err("type", "must equal 'workorder'");

  // Only wonum is required.
  if (!isStr(newDoc.wonum)) err("wonum", "is required and must be a non-empty string");

  // Everything else is validated only when present.
  if (present(newDoc.description) && String(newDoc.description).length > 100) err("description", "max length is 100 chars");

  var STATUS = ["WAPPR","APPR","WMATL","WSCH","INPRG","WPCOND","COMP","CLOSE","CAN"];
  if (present(newDoc.status) && STATUS.indexOf(newDoc.status) === -1) err("status", "invalid status '" + newDoc.status + "'");

  var WORKTYPE = ["CM","PM","EM","PdM","CAL","INSP","GEN"];
  if (present(newDoc.worktype) && WORKTYPE.indexOf(newDoc.worktype) === -1) err("worktype", "invalid worktype '" + newDoc.worktype + "'");

  if (present(newDoc.wopriority)) {
    var pr = newDoc.wopriority;
    if (typeof pr !== "number" || pr < 1 || pr > 5 || (pr % 1 !== 0)) err("wopriority", "must be an integer 1..5");
  }

  if (newDoc.aob_source) {
    var AGENTS = ["iot","fmsr","tsfm","wo","human"];
    var TRIGGERS = ["anomaly_detection","forecast","failure_mode","rule_monitoring","inspection","manual"];
    if (present(newDoc.aob_source.agent) && AGENTS.indexOf(newDoc.aob_source.agent) === -1) err("aob_source.agent", "invalid agent");
    if (present(newDoc.aob_source.trigger_type) && TRIGGERS.indexOf(newDoc.aob_source.trigger_type) === -1) err("aob_source.trigger_type", "invalid trigger_type");
  }
}

by_scenario.map:
function (doc) {
  if (doc.type === "workorder" && doc.aob_source && doc.aob_source.scenario_id) {
    emit(doc.aob_source.scenario_id, doc.wonum);
  }
}

by_agent.map:
function (doc) {
  if (doc.type === "workorder" && doc.aob_source && doc.aob_source.agent) {
    emit([doc.aob_source.agent, doc.aob_source.trigger_type], null);
  }
}

backlog.map:
function (doc) {
  // Non-terminal (open) work orders, keyed [siteid, status] for week-at-a-glance.
  var TERMINAL = { COMP: 1, CLOSE: 1, CAN: 1 };
  if (doc.type === "workorder" && !TERMINAL[doc.status]) emit([doc.siteid, doc.status], null);
}

children.map:
function (doc) {
  // Task / sub-WO rows keyed by parent for breakdown lookups.
  if (doc.type === "workorder" && doc.parent) emit([doc.parent, doc.taskid || 0], doc.wonum);
}
